const users = items[0].json.users;

function parseDate(input) {
  if (!input) return null;
  const date = new Date(input);
  return date.toISOString().slice(0, 19).replace('T', ' ');
}

function escapeString(val) {
  return val ? val.toString().replace(/'/g, "''") : '';
}

const values = users.map(user => {
  return `(
    '${escapeString(user.id)}',
    '${escapeString(user.first_name)}',
    '${escapeString(user.full_name)}',
    '${escapeString(user.email)}',
    '${escapeString(user.alias)}',
    ${user.dob ? `'${escapeString(user.dob)}'` : 'NULL'},
    '${escapeString(user.phone)}',
    '${escapeString(user.created_by?.name)}',
    '${escapeString(user.created_by?.id)}',
    ${user.Shift_Effective_From ? `'${parseDate(user.Shift_Effective_From)}'` : 'NULL'},
    '${escapeString(user.zuid)}',
    ${user.confirm === true ? 1 : 0},
    '${escapeString(JSON.stringify(user.territories || []))}',
    '${escapeString(user.date_format)}',
    '${escapeString(user.status)}',
    '${escapeString(user.profile?.id)}',
    '${escapeString(user.profile?.name)}',
    ${user.created_time ? `'${parseDate(user.created_time)}'` : 'NULL'},
    ${user.Modified_Time ? `'${parseDate(user.Modified_Time)}'` : 'NULL'}
  )`;
});

return [{ json: { bulkValues: values.join(',\n') } }];
